class Solution {
    public int minDeletionSize(String[] strs) {
        int n = strs.length;
        int m = strs[0].length();
        int[] dp = new int[m];
        for (int j = 0; j < m; ++j) {
            dp[j] = 1;
            for (int i = 0; i < j; ++i) {
                boolean flag = true;
                for (int k = 0; k < n - 1; ++k)
                    flag = flag && (strs[k].charAt(i) <= strs[k].charAt(j));
                dp[j] = flag ? Math.max(dp[j], dp[i] + 1) : dp[j];
            }
        }

        int maxLength = 0;
        for (int num : dp)
            maxLength = Math.max(maxLength, num);

        return m - maxLength;
    }
}
```


